import React, { useState } from 'react';

function App() {
  const [showAssistant, setShowAssistant] = useState(false);
  const [activeTab, setActiveTab] = useState('home'); // Håller koll på vilken flik vi är på

  const stats = [
    { label: 'KM IDAG', value: '124', icon: '🧭' },
    { label: 'KÖRTID', value: '2h 15m', icon: '⚡' },
    { label: 'STOPP', value: '3', icon: '📍' },
  ];

  // Denna funktion bestämmer vad som visas beroende på vilken knapp du tryckt på i menyn
  const renderContent = () => {
    if (activeTab === 'home') {
      return (
        <div style={{ padding: '20px' }}>
          <header style={{ marginBottom: '30px' }}>
            <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: '0 0 5px 0' }}>Hej Buddy! 🚐</h1>
            <p style={{ color: '#636E72', margin: '0', fontSize: '14px' }}>Solen går ner om 3 timmar. Letar vi nattplats?</p>
          </header>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '15px', marginBottom: '40px' }}>
            {stats.map((stat, i) => (
              <div key={i} style={statCardStyle}>
                <div style={{ fontSize: '20px', marginBottom: '8px' }}>{stat.icon}</div>
                <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#000' }}>{stat.value}</div>
                <div style={{ fontSize: '9px', color: '#95A5A6', textTransform: 'uppercase', marginTop: '2px', fontWeight: '600', letterSpacing: '0.5px' }}>{stat.label}</div>
              </div>
            ))}
          </div>

          <section>
            <h2 style={{ fontSize: '16px', fontWeight: 'bold', marginBottom: '15px', color: '#000' }}>Vad vill du göra nu?</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
              <button style={actionButtonStyle}>
                <span style={{ fontSize: '20px', marginBottom: '6px' }}>📸</span>
                <span>Fota & Logga</span>
              </button>
              <button onClick={() => setActiveTab('convoy')} style={actionButtonStyle}>
                <span style={{ fontSize: '20px', marginBottom: '6px' }}>🫂</span>
                <span>Min Konvoj</span>
              </button>
            </div>
          </section>
        </div>
      );
    } else if (activeTab === 'convoy') {
      return (
        <div style={{ padding: '20px', textAlign: 'center', paddingTop: '50px' }}>
          <h1 style={{ fontSize: '24px', color: '#2D5A27' }}>Min Konvoj 🫂</h1>
          <p style={{ color: '#636E72' }}>Här kommer vi snart bygga vår gemensamma karta och röstningsfunktion för hela sällskapet!</p>
        </div>
      );
    } else if (activeTab === 'logbook') {
      return (
        <div style={{ padding: '20px', textAlign: 'center', paddingTop: '50px' }}>
          <h1 style={{ fontSize: '24px', color: '#2D5A27' }}>Loggbok 📖</h1>
          <p style={{ color: '#636E72' }}>Här samlas dina minnen. Snart kan du exportera din resa som en snygg TravelMap-film!</p>
        </div>
      );
    }
  };

  return (
    // paddingBottom: 80px gör att innehållet inte hamnar bakom menyn
    <div style={{ backgroundColor: '#F5F2ED', minHeight: '100vh', fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif', color: '#2D3436', position: 'relative', overflow: 'hidden', paddingBottom: '80px', maxWidth: '480px', margin: '0 auto' }}>

      {/* Här ritas den aktuella vyn ut (Hem, Konvoj eller Loggbok) */}
      {renderContent()}

      {/* UTVECKLARKNAPP (Bara synlig på Hem-skärmen) */}
      {activeTab === 'home' && (
        <button 
          onClick={() => setShowAssistant(true)}
          style={{ position: 'fixed', bottom: '100px', right: '20px', backgroundColor: '#D35400', color: 'white', border: 'none', padding: '15px', borderRadius: '50px', fontWeight: 'bold', cursor: 'pointer', boxShadow: '0 4px 10px rgba(0,0,0,0.2)', zIndex: 10 }}>
          🛑 Stopp
        </button>
      )}

      {/* --- PREMIUM-ANIMERAD ASSISTENT --- */}
      <div style={{ ...overlayStyle, opacity: showAssistant ? 1 : 0, pointerEvents: showAssistant ? 'auto' : 'none' }}>
        <div style={{ ...bottomSheetStyle, transform: showAssistant ? 'translateY(0)' : 'translateY(100%)' }}>
          <h2 style={{ fontSize: '22px', color: '#2D5A27', marginBottom: '5px', marginTop: '0' }}>Härlig plats! 🌲</h2>
          <p style={{ color: '#636E72', marginBottom: '25px', lineHeight: '1.5', fontSize: '15px' }}>
            Jag känner att vi har stannat. Det är 18°C och soligt just nu. Vill du spara platsen i loggboken?
          </p>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <button style={primaryBtnStyle}>☀️ Logga väder & plats</button>
            <button style={secondaryBtnStyle}>📸 Lägg till ett foto</button>
            <button style={secondaryBtnStyle}>🗺️ Dela med Konvojen</button>
          </div>

          <button onClick={() => setShowAssistant(false)} style={cancelBtnStyle}>Nej, vi ska bara sträcka på benen</button>
        </div>
      </div>

      {/* --- BOTTENMENY --- */}
      <nav style={navBarStyle}>
        <button onClick={() => setActiveTab('home')} style={activeTab === 'home' ? activeNavItemStyle : navItemStyle}>
          <span style={{ fontSize: '24px', filter: activeTab === 'home' ? 'none' : 'grayscale(100%)' }}>🧭</span>
          <span style={{ fontSize: '10px', marginTop: '4px', fontWeight: activeTab === 'home' ? 'bold' : 'normal' }}>Hem</span>
        </button>
        <button onClick={() => setActiveTab('convoy')} style={activeTab === 'convoy' ? activeNavItemStyle : navItemStyle}>
          <span style={{ fontSize: '24px', filter: activeTab === 'convoy' ? 'none' : 'grayscale(100%)' }}>🫂</span>
          <span style={{ fontSize: '10px', marginTop: '4px', fontWeight: activeTab === 'convoy' ? 'bold' : 'normal' }}>Konvoj</span>
        </button>
        <button onClick={() => setActiveTab('logbook')} style={activeTab === 'logbook' ? activeNavItemStyle : navItemStyle}>
          <span style={{ fontSize: '24px', filter: activeTab === 'logbook' ? 'none' : 'grayscale(100%)' }}>📖</span>
          <span style={{ fontSize: '10px', marginTop: '4px', fontWeight: activeTab === 'logbook' ? 'bold' : 'normal' }}>Loggbok</span>
        </button>
      </nav>

    </div>
  );
}

